import yaml
from pathlib import Path
from dataclasses import dataclass

@dataclass
class WaiverCheckResult:
    passed: bool
    active_waivers: list[str]
    expired_waivers: list[str]
    warnings: list[str]

def check_deployment_waivers(project: str, register_path: str = "waiver-register.yaml") -> WaiverCheckResult:
    # Load waiver register from governance repo
    with open(register_path) as f:
        register = yaml.safe_load(f)

    from datetime import date
    today = date.today()
    active, expired, warnings = [], [], []

    for w in register.get("waivers", []):
        if w["project"] != project:
            continue

        expiry = date.fromisoformat(w["expires"])
        if expiry < today:
            expired.append(w["id"])
        else:
            active.append(w["id"])
            days_left = (expiry - today).days
            if days_left < 30:
                warnings.append(f"{w['id']} expires in {days_left} days — renewal required")

            # Check overdue conditions
            for cond in w.get("conditions", []):
                if not cond["satisfied"]:
                    due = date.fromisoformat(str(cond["due"]))
                    if due < today:
                        warnings.append(
                            f"{w['id']} condition overdue: {cond['description'][:60]}"
                        )

    passed = len(expired) == 0  # expired waivers block deployment
    return WaiverCheckResult(passed=passed, active_waivers=active,
                             expired_waivers=expired, warnings=warnings)

# In CI/CD pipeline:
result = check_deployment_waivers("FNOL-GenAI")
if not result.passed:
    print(f"DEPLOY BLOCKED: expired waivers {result.expired_waivers}")
    raise SystemExit(1)
for w in result.warnings:
    print(f"WARNING: {w}")
print(f"Waiver check passed — {len(result.active_waivers)} active waivers: {result.active_waivers}")
